diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..b903863bd60f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -3552,9 +3552,70 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
           }
       }
     }
+
+  case Intrinsic::fshl:
+  case Intrinsic::fshr: {
+    Value *Op0 = II->getArgOperand(0);
+    Value *Op1 = II->getArgOperand(1);
+    Value *ShAmt = II->getArgOperand(2);
+    Type *Ty = II->getType();
+    unsigned BitWidth = Ty->getScalarSizeInBits();
+
+    // fshl(x, 0, y) -> shl(x, y) if y is in [0, BitWidth)
+    if (IID == Intrinsic::fshl && match(Op1, m_Zero())) {
+      KnownBits ShAmtKnown = computeKnownBits(ShAmt, 0, II);
+      if (ShAmtKnown.getMaxValue().ult(BitWidth))
+        return BinaryOperator::Create(Instruction::Shl, Op0, ShAmt);
+    }
+
+    // fshr(0, x, y) -> lshr(x, y) if y is in [0, BitWidth)
+    if (IID == Intrinsic::fshr && match(Op0, m_Zero())) {
+      KnownBits ShAmtKnown = computeKnownBits(ShAmt, 0, II);
+      if (ShAmtKnown.getMaxValue().ult(BitWidth))
+        return BinaryOperator::Create(Instruction::LShr, Op1, ShAmt);
+    }
+
     [[fallthrough]];
   }
   case Intrinsic::vector_reduce_xor: {
+    // Handle funnel shift intrinsics that fall through to here
+    if (IID == Intrinsic::fshl || IID == Intrinsic::fshr) {
+      Value *Op0 = II->getArgOperand(0);
+      Value *Op1 = II->getArgOperand(1);
+      Value *ShAmt = II->getArgOperand(2);
+      Type *Ty = II->getType();
+      unsigned BitWidth = Ty->getScalarSizeInBits();
+
+      // fshl(0, 0, Y) -> 0, fshr(0, 0, Y) -> 0
+      if (match(Op0, m_Zero()) && match(Op1, m_Zero())) {
+        return replaceInstUsesWith(CI, Constant::getNullValue(Ty));
+      }
+
+      // fshl(X, 0, Y) -> shl(X, Y) if Y is known < BitWidth
+      if (IID == Intrinsic::fshl && match(Op1, m_Zero())) {
+        const APInt *C;
+        if (match(ShAmt, m_APInt(C)) && C->ult(BitWidth)) {
+          return replaceInstUsesWith(CI, Builder.CreateShl(Op0, ShAmt));
+        }
+        KnownBits ShAmtKnown = computeKnownBits(ShAmt, 0, II);
+        if (ShAmtKnown.getMaxValue().ult(BitWidth)) {
+          return replaceInstUsesWith(CI, Builder.CreateShl(Op0, ShAmt));
+        }
+      }
+
+      // fshr(0, X, Y) -> lshr(X, Y) if Y is known < BitWidth
+      if (IID == Intrinsic::fshr && match(Op0, m_Zero())) {
+        const APInt *C;
+        if (match(ShAmt, m_APInt(C)) && C->ult(BitWidth)) {
+          return replaceInstUsesWith(CI, Builder.CreateLShr(Op1, ShAmt));
+        }
+        KnownBits ShAmtKnown = computeKnownBits(ShAmt, 0, II);
+        if (ShAmtKnown.getMaxValue().ult(BitWidth)) {
+          return replaceInstUsesWith(CI, Builder.CreateLShr(Op1, ShAmt));
+        }
+      }
+    }
+
     if (IID == Intrinsic::vector_reduce_xor) {
       // Exclusive disjunction reduction over the vector with
       // (potentially-extended) i1 element type is actually a
@@ -3753,6 +3814,8 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   return visitCallBase(*II);
 }

